INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098930f","title":"Huck","author":"Mark Millar","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001709175/140/904f/Mark_Millar__Huck.jpg","isbn":"1632157292","publisher":"Image Comics","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"In a quiet seaside town, a gas station clerk named Huck secretly uses his special gifts to do a good deed each day. When his story leaks, a media firestorm erupts, bringing him uninvited fame. As pieces of Huck''s past begin to resurface, it''s no longer clear who his friends are – or whose lives may be in danger.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999119,"hdCover":""},{"id":"098930e","title":"Nemesis: Reloaded","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1008773344/140/8e47/Mark_Millar__Nemesis_Reloaded.jpg","isbn":"978-1534399907","publisher":"Image Comics","pubDate":"2023","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"The world''s most evil comic book character is back! Who is Nemesis and why does this eccentric billionaire who dresses up in a mask and cape want to terrorise people instead of helping them? Isn''t that how this is supposed to go? Trigger warning: Too violent and just too cool for some! Don''t say we didn''t warn you. Collecting the entire arc by superstar creative team Mark Millar and Jorge Jiménez.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999118,"hdCover":""},{"id":"098930d","title":"Superior","author":"Марк Миллар,Лейнил Фрэнсис Ю","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000762374/140/fbe2/__Superior.jpg","isbn":"978-0-7851-5317-7","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Simon Pooni was a normal kid with a great life, until multiple sclerosis hit. He lost the ability to walk, went blind in one eye and sometimes could barely speak. Every night, Simon would pray that his disease would somehow go away. \"Somehow\" turned out to be a magic monkey named Orman, who granted Simon one wish. And the 12-year-old boy stood transformed into a real-life version of legendary comic-book hero Superior. Simon spent one glorious week saving those in need, averting natural disasters - becoming the mostbeloved man on the planet. But Orman ominously cautioned Simon all would be explained in one week. Will Simon be forced to go back to life in a wheelchair after being the world''s greatest hero? Faced with adversity, will he prove himself to truly be...Superior?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999117,"hdCover":""},{"id":"098930c","title":"The Magic Order. Volume 1","author":"Марк Миллар,Оливье Койпель","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003018920/140/4180/__The_Magic_Order._Volume_1.jpg","isbn":"978-1534308718","publisher":"Image Comics","pubDate":"2019","language":"","series":"The Magic Order","genres":[],"annotation":"We live in a world where we’ve never seen a monster, and The Magic Order is the reason we sleep safely in our beds. Magic meets the Mob in The Magic Order, as five families of magicians -- sworn to protect our world for generations -- must battle an enemy who’s picking them off one by one. By day, they live among us as our neighbors, friends and co-workers, but by night they are the sorcerers, magicians and wizards that protect us from the forces of darkness...unless the darkness gets them first.  Collects THE MAGIC ORDER #1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999116,"hdCover":""},{"id":"098930b","title":"Reborn","author":"Марк Миллар,Грег Капулло,Джонатан Глейпион","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002434236/140/a650/__Reborn.jpg","isbn":"978-1534301580","publisher":"Image Comics","pubDate":"2017","language":"","series":"","genres":["Исторические приключения"],"annotation":"The Millar-Capullo smash-hit sell out REBORN is here. Where do you go when you die? Not heaven or hell. somewhere else. Somewhere you have to fight to survive. Somewhere the people from the past are waiting for you—the good and the bad.  Superstar creators MARK MILLAR and GREG CAPULLO join forces to create the sci-fi story of the year, collecting issues 1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999115,"hdCover":""},{"id":"098930a","title":"Supercrooks 1: The Heist","author":"Mark Millar","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001506807/140/2d2c/Mark_Millar__Supercrooks_1_The_Heist.jpg","isbn":"0785165444,  978-0785165446","publisher":"Marvel Comics","pubDate":"2013","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"One last heist. That''s what they all say, right? Just one final score, and everyone can retire and take up fishing. Thing is, the jails are filled with super villains who thought the same thing, and got busted. But the Heat''s in a jam. He''s run up the kind of gambling debt that - if he can''t pay it back in cash - will be paid in blood. Nobody wants to see the most beloved supercrook of all time rubbed out by the mob - especially his biggest fan, Johnny Bolt. And Johnny''s got a plan to help the Heat and make all his buddies disgustingly rich at the same time. Unfortunately for Johnny''s recruits, they have to head to Spain and rob the world''s most notorious super villain blind. And that''s where things get tricky.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999114,"hdCover":""},{"id":"0989309","title":"Наследие Юпитера. Том 1","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006271440/140/82b5/Mark_Millar__Nasledie_Yupitera._Tom_1.jpg","isbn":"978-5-04-123222-1","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Тайны. Одиночество. Алкоголь. Супружеская измена. Зависть. Безупречность. Даже ваши герои — всего лишь люди. Легендарный писатель Марк Миллар (\"Гражданская война\", \"Росомаха. Старик Логан\", \"Росомаха. Враг государства\", \"Супермен. Красный сын\") наглядно показывает, что наличие сверхспособностей никого не делает святым. Те, кто спасает мир от вторжения инопланетных захватчиков или козней очередного сумасшедшего учёного, легко могут проиграть схватку своим собственным демонам. И вот герои уже врут, предают, разбивают сердца своим близким и идут на сделки с совестью.  Но сколь многое человечество готово простить своим защитникам? И как далеко зайдут сами герои?  Включает выпуски \"Круга Юпитера\" № 1–6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999113,"hdCover":""},{"id":"0989308","title":"Убивашка в Колумбии","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004136511/140/c3f2/Mark_Millar__Ubivashka_v_Kolumbii.jpg","isbn":"978-5-04-111610-1","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Комильфо. Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Первая остановка: Колумбия. Мать, которая хочет отомстить за смерть сына, уговаривает Убивашку разобраться с его убийцей, но у Минди другие планы на самого опасного киллера Пальмиры. Вооружившись до зубов, Убивашка освобождает Фабио \"Мано\" Мендозу, чтобы с его помощью истребить всех местных гангстеров, а потом заставить его выступить проотив бывших подельников. Это термоядерное и полное ультранасилия возвращение самой смертоносной двенадцатилетки – дело рук легендарного сценариста Марка Миллара (\"Мордобой\", \"Kingsman: секретная служба\") и художника Рикардо Лопеса Ортиса (Wolf, \"Гражданская война II: Кингпин\").","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999112,"hdCover":""},{"id":"0989307","title":"Императрица. Книга 1","author":"Марк Миллар","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002698845/140/0804/Mark_Millar__Imperatritsa._Kniga_1.jpg","isbn":"978-5-04-089537-3","publisher":"Fanzon","pubDate":"2017","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Вместе с неунывающей Эмпорией вам предстоит окунуться в пучины межпланетных войн, посетить погибшие миры, ускользнуть от пасти огромного чудовища, едва спастись от плена подлых работорговцев и безумного жреца, мечтающего принести императрицу в жертву!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999111,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989306","title":"Мордобой 2. Пролог: Убивашка","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001443498/140/abe9/Mark_Millar_Dzhon_Romita_ml.__Mordoboj_2._Prolog_Ubivashka.jpg","isbn":"978-5-91339-339-5","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Минди Маккриди освоила сотню способов убить человека. Её отец, супергерой по имени Большой Папочка, сделал всё для этого. Она использовала свои навыки, чтобы очистить город от бандитов, суперзлодеев и прочих сомнительных личностей. Так почему же общение в школе с популярными девчонками для нее стало самым тяжким испытанием? Теперь, когда Большого Папочки уже нет, Убивашка изо всех сил пытается жить \"нормальной жизнью\" с мамой и отчимом. Поэтому она заключает сделку с начинающим супергероем по имени Мордобой: она поможет ему выжить, если тот поможет ей подружиться с одноклассницами. Но в городе новый крёстный отец, так что \"нормальная\" жизнь снова откладывается.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999110,"hdCover":""},{"id":"0989305","title":"Мордобой 3","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001489973/140/d5e4/Mark_Millar_Dzhon_Romita_ml.__Mordoboj_3.jpg","isbn":"978-5-91339-353-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Кто бы мог подумать, что восемнадцатилетний подросток может стать СУПЕРГЕРОЕМ?  Дэйву Лизевски это удалось - после долгих и напряженных тренировок девчонкой, известной как Убивашка, он начал свою супергеройскую карьеру в роли Мордобоя. Они с Убивашкой выпустили против мафии... и победили. Но и у победы есть своя цена.  Теперь, когда Убивашка оказалась в тюрьме, Мордобой должен встать на её место и повести за собой деморализованную команду борцов с преступностью \"Справедливость Навсегда\", несмотря на то, что полиция объявила героев в масках вне закона.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999109,"hdCover":""},{"id":"0989304","title":"Особо опасен","author":"Марк Миллар,Дж. Дж. Джонс,Пол Маунтс","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000311470/140/5859/__Osobo_opasen.jpg","isbn":"978-5-17-054673-2","publisher":"АСТ, Астрель","pubDate":"2008","language":"Русский","series":"Кинороман","genres":["Современная зарубежная литература","Зарубежная фантастика"],"annotation":"Фильм \"Особо опасен\" - сенсационная премьера этого года! В нем приняли участие Джеймс МакЭвой (Уэсли Гибсон), Морган Фриман (Слоан), Константин Хабенский (Истребитель) и Анджелина Джоли (Фокс). В этой книге представлены первые страницы графического романа \"Wanted\", легшего в основу захватывающего фильма.  Уэсли Гибсон (Джеймс МакЭвой) - зануда и нытик, целыми днями торчащий в офисе. Босс его унижает, подружка ему изменяет. Его жизнь катится в никуда! Обнаружив, что отец, бросивший его в раннем детстве, зверски убит, Уэс оказывается втянут в тайное общество киллеров под названием \"Братство\". За его обучение берется опытная наставница Фокс (Анджелина Джоли), и этот когда-то прикованный к офисному креслу тихоня развивает молниеносную реакцию и сверхчеловеческую скорость. Однако уже на первом задании Уэс понимает, что есть вещи посложнее, чем вершить судьбы других людей: набраться храбрости и стать хозяином собственной жизни!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999108,"hdCover":""},{"id":"0989303","title":"Мордобой 2","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001443515/140/abe9/Mark_Millar_Dzhon_Romita_ml.__Mordoboj_2.jpg","isbn":"978-5-91339-340-1","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Обладая минимальной физподготовкой и парой дубинок, он надел маску и решил стать настоящим супергероем по имени Мордобой. И он преуспел в этом. Более чем. Мордобой и Уби-черныйпояс-вашка бросили Мафии...и победили. Неожиданно, стало модно быть супергероем. Какой же следующий логичный шаг предпринял Мордобой. Присоединился к команде супергероев. Однако бывший союзник Мордобоя, Красный туман, считает, что герои - это прошлый век. Он станет самым известным суперзлодеем. Теперь, когда конфликт перешел в массовое столкновение на Таймс-сквер, сможет ли наш герой выжить?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999107,"hdCover":""},{"id":"0989302","title":"Мордобой","author":"Марк Миллар, Джон Ромита мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001388604/140/8f54/Mark_Millar_Dzhon_Romita_ml.__Mordoboj.jpg","isbn":"978-5-91339-324-1","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"О маньяках и расследованиях. Профайлинг и прочее.И книги на «похоронную» тему","genres":["Комиксы","манга","графические романы"],"annotation":"Легендарный комикс Kick-Ass Марка Миллара и Джона Ромиты-младшего - впервые на русском языке!  Дэйв Лизевски - обычный американский подросток. Ему нравятся девочки, видеоигры и комиксы. Но иногда этого становится недостаточно. Превращение в Мордобоя, первого в мире настоящего супергероя, мгновенно делает его Интернет-знаменитостью.  Обыватели любят его, а преступники боятся. Но вскоре он встречает смертельное оружие в юбке по имени Убивашка и её пугающего напарника Большого Папочку, и дела начинают набирать иной, более серьезный и жестокий оборот.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999106,"hdCover":""},{"id":"0989301","title":"Daytripper. Мечтатель","author":"Фабио Мун,Габриэль Ба","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003326300/140/a4fe/__Daytripper._Mechtatel.jpg","isbn":"978-5-389-17160-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Знакомьтесь: Браз де Олива Домингос. Чудо-ребенок, сын знаменитого бразильского писателя. Днем он сочиняет некрологи, а по ночам мечтает стать известным литератором, придумывая финалы чужих жизней, хотя его собственная только-только началась.  Но когда Браз заметит это? В 21 год, после встречи с девушкой его мечты? В 11 лет, после первого поцелуя? Или позже, после рождения его сына? Или до того, как он обретет свой писательский голос?  Каждый день в жизни Браза – точно страница книги. На каждой странице мы встречаем тех, кто сделал его именно таким: отец и мать, сын и лучший друг, первая любовь и любовь всей жизни. И, как во всех великих произведениях, в каждом дне его ждет новый поворот, который нашему герою не преодолеть...  Лауреаты премии Айснера близнецы Фабио Мун и Габриэль Ба рассказывают волшебную, таинственную и волнующую историю самой жизни. Во время этого поразительного лирического путешествия авторы используют минуты тишины, чтобы задаться серьезными вопросами.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999105,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
