  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892f5","title":"Batman: The Caped Crusader Vol. 3","author":"Марв Вульфман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470906/140/7363/Marv_Vulfman__Batman_The_Caped_Crusader_Vol._3.jpg","isbn":"978-1401294274","publisher":"DC","pubDate":"2019","language":"","series":"","genres":[],"annotation":"A new collection featuring the legendary 1990s Batman epics \"Dark Knight, Dark City\" and more.  THE CAPED CRUSADER  Batman leaves the crime-riddled streets of Gotham City for the snowy cityscape of Moscow to hunt a disciple of the KGBeast known as the NKVDemon who is mercilessly killing members of the Soviet Union''s Politburo. Bruce Wayne must first ditch the Soviet agents keeping a watchful eye on him to don his cowl and cape and confront this new Soviet assassin.  Back in Gotham, Batman confronts a new scheme by the Penguin who has enlisted the help of Harold, a hunchback genius who has invented a technology to control birds to use them as an unconventional army--and as assassins. Then the Caped Crusader must deal with a newly vicious and bloodthirsty Riddler, as the villain kidnaps innocent babies and leads Batman through a labyrinth of grim trials to rescue them.  An all-star cast of talent, led by legendary writer Marv Wolfman (Crisis on Infinite Earths) and featuring the dynamic art of Jim Aparo (The Brave and the Bold), and Norm Breyfogle (Detective Comics), presents Batman: The Caped Crusader Vol. 3,","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999093,"hdCover":""},{"id":"09892f4","title":"Batman: The Caped Crusader Vol. 4","author":"Alan Grant","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470909/140/1c09/Alan_Grant__Batman_The_Caped_Crusader_Vol._4.jpg","isbn":"978-1779500304","publisher":"DC","pubDate":"2020","language":"","series":"","genres":[],"annotation":"Gotham City has endured much through its dark, twisted history, and even the cosmic changes wrought by the Crisis on Infinite Earths couldn''t give the town a fresh start--the grime is in its DNA. The Crisis did, though, allow for the reintroduction of familiar foes, albeit with a fresh take on the Caped Crusader featuring a back-to-basics approach to crime-fighting.  This new collection of 1990s Batman stories reveals the origin story of Tim Drake as Robin. With crime running amok and an overwhelming sense of responsibility to help all, Batman considers partnering up. Commissioner Gordon rekindles an old flame and Batman decides whether or not he is ready to fight crime with a partner by his side.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999092,"hdCover":""},{"id":"09892f3","title":"Batman: The Caped Crusader Vol. 2","author":"Марв Вульфман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470903/140/a7bf/Marv_Vulfman__Batman_The_Caped_Crusader_Vol._2.jpg","isbn":"978-1401287825","publisher":"DC","pubDate":"2019","language":"","series":"","genres":[],"annotation":"A new collection featuring the legendary 1990s Batman epics \"The Many Deaths of Batman\" and \"A Lonely Place of Dying.\"  This new collection of 1980s Batman tales includes the legendary story \"A Lonely Place of Dying,\" in which a new Robin emerges in the form of computer hacker Tim Drake, who rescues Batman from The Joker and Two-Face. This volume also includes the mystery story \"The Many Deaths of Batman,\" and a run of stories in which the Dark Knight must stop crime boss Zucco.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999091,"hdCover":""},{"id":"09892f2","title":"Batman: The Caped Crusader Vol. 1","author":"Джим Старлин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007470900/140/fba5/Dzhim_Starlin__Batman_The_Caped_Crusader_Vol._1.jpg","isbn":"978-1401281366","publisher":"DC","pubDate":"2018","language":"","series":"","genres":[],"annotation":"Gotham City has endured much through its dark, twisted history, and even the cosmic changes wrought by the Crisis on Infinite Earths couldn''t give the town a fresh start--the grime is in its DNA. The Crisis did, though, allow for the reintroduction of familiar foes, albeit with a fresh take on the Caped Crusader featuring a back-to-basics approach to crime-fighting.  Criminals don''t always wear a colorful costumes: some just stalk the shadows with sinister plots and evil intentions. A new threat, a fearsome assassin known as the KGBeast, is prowling the streets of Gotham City and he''s out to dismantle America''s Strategic Defense Initiative. After saving the United States government, Batman must then solve the mystery of ten murdered women before the killer claims even more victims!  An all-star cast of talent, led by writer Jim Starlin (Batman: The Cult, Mystery In Space) and the dynamic art duo of Jim Aparo (The Brave and The Bold, Batman & The Outsiders) and Mike DeCarlo (The Legion Of Super-Heroes), present Batman: The Caped Crusader Vol. 1,","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999090,"hdCover":""}]');

