FROM json_each('[{"id":"09892f1","title":"Сага Электра","author":"Фрэнк Миллер","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007476609/140/7147/Frenk_Miller__Saga_Elektra.jpg","isbn":"","publisher":"Марвел","pubDate":"1983","language":"","series":"#168, 174-182 и 187-190","genres":[],"annotation":"Электра уехала изучать боевые искусства в Японии, где вскоре примкнула к тайной организации боевых искусств, возглавляемой Стиком, который также был сэнсэем у Мёрдока. Электра провела там год и значительно развила свои навыки в боевых искусствах. Но Стик попросил её выйти из группы, потому что её по-прежнему переполняет боль от смерти отца и она испытывает ненависть к миру. Электра уходит к своему старому сэнсэю.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999089,"hdCover":""},{"id":"09892f0","title":"PLUTO: Urasawa x Tezuka, Volume 001","author":"Naoki Urasawa","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001133418/140/f64b/Naoki_Urasawa__PLUTO_Urasawa_x_Tezuka_Volume_001.jpg","isbn":"1421519186,  978-1-42-151918-0","publisher":"VIZ Media LLC","pubDate":"2009","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"In a distant future where sentient humanoid robots pass for human, someone or some thing is out to destroy the seven great robots of the world. Europol''s top detective Gesicht is assigned to investigate these mysterious robot serial murders. the only catch is that he himself is one of the seven targets.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999088,"hdCover":""},{"id":"09892ef","title":"Chew, Volume 5","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001994501/140/6ca8/Dzhon_Lajman_Rob_Gillori__Chew_Volume_5.jpg","isbn":"","publisher":"","pubDate":"","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"This gorgeous oversized edition collects the ninth and tenth storylines of the New York Times Best Selling, Harvey and multiple Eisner Award series, as well as the beloved one-shot WARRIOR CHICKEN POYO. Collects CHEW #41-#50 plus WARRIOR CHICKEN POYO.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999087,"hdCover":""},{"id":"09892ee","title":"Chew, Volume 6","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002698655/140/4d69/Dzhon_Lajman_Rob_Gillori__Chew_Volume_6.jpg","isbn":"1534301801","publisher":"Image Comics","pubDate":"2017","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы"],"annotation":"The final story arc of Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats. Mysteries are solved, secrets are reveals and lives are lost. Many, many lives. This is the end of the line for the New York Times Best Selling, Harvey and multiple Eisner Award-winner series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999086,"hdCover":""},{"id":"09892ed","title":"Chew, Volume 4","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002765999/140/669f/Dzhon_Lajman_Rob_Gillori__Chew_Volume_4.jpg","isbn":"163215031X","publisher":"Image Comics","pubDate":"2014","language":"Английский","series":"","genres":[],"annotation":"A glorious Hardcover collection of CHEW #31-#40 with all the fixin''s. Anthony and Antonelle Chu are fraternal twins. Tony and Toni. Each with their an extraordinary, albeit diametrically opposed, ability. Tony is Cibopathic, able to get psychic sensations of the past of anything he bites into or ingests. Toni is Cibovoyant, able to flash onto a vision of the future of any living thing she bit into or ingested.  Tony is alive. Toni is dead. Toni has been murdered. Tony has vowed to catch her killer. Toni is going to help.  Presenting a new storyline of the New York Times Best Selling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999085,"hdCover":""},{"id":"09892ec","title":"Chew Volume 12: Sour Grapes","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002141751/140/0d99/Dzhon_Lajman_Rob_Gillori__Chew_Volume_12_Sour_Grapes.jpg","isbn":"978-1534300316","publisher":"Image Comics","pubDate":"2017","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"The final story arc of Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats. Mysteries are solved, secrets are revealed, and lives are lost. Many, many lives. This is the end of the line for the New York Times bestselling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999084,"hdCover":""},{"id":"09892eb","title":"Chew Volume 11: The Last Suppers","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002004257/140/02f4/Dzhon_Lajman_Rob_Gillori__Chew_Volume_11_The_Last_Suppers.jpg","isbn":"978-1632156815","publisher":"Image Comics","pubDate":"2016","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats, is getting closer to finding the answers he’s been looking for—answers about the bird flu that killed millions, answers about the conspiracy to keep people from discovering the truth. And the only thing standing in Tony’s way is his Mason Savoy, fellow cibopath, ex-mentor—and unrepentant murderer! Presenting the second-to-last storyline of the New York Times Best Selling, Harvey and multiple Eisner Award-winner series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999083,"hdCover":""},{"id":"09892ea","title":"Chew Volume 10: Blood Puddin''","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493868/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_10_Blood_Puddin039.jpg","isbn":"978-1632153968","publisher":"Image Comics","pubDate":"2015","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"CAN TONY STOP HIS MOST DANGEROUS ENEMY? Presenting a new storyline of the New York Times Best Selling, Harvey- and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999082,"hdCover":""},{"id":"09892e9","title":"Chew Volume 9: Chicken Tenders","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493867/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_9_Chicken_Tenders.jpg","isbn":"978-1632152893","publisher":"Image Comics","pubDate":"2015","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from what he eats, has been busy — busy settling into married life, and busy investigating one assignment after another that takes him to the most remote corners of the planet. Meanwhile, the people closest to Tony are conspiring to take on the brutal killer who murdered Tony’s twin sister. And this conspiracy includes Tony’s partner, his arch enemy — and his teenage daughter!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999081,"hdCover":""},{"id":"09892e8","title":"Chew Volume 8: Family Recipes","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001493866/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_8_Family_Recipes.jpg","isbn":"978-1607069386","publisher":"Image Comics","pubDate":"2014","language":"Английский","series":"Chew","genres":[],"annotation":"Anthony and Antonelle Chu are fraternal twins. Tony and Toni. Each with their own extraordinary, albeit diametrically opposed, ability. Tony is Cibopathic, able to get psychic sensations of the past of anything he bites into or ingests. Toni is Cibovoyant, able to flash onto a vision of the future of any living thing she bit into or ingested. Tony is alive. Toni is dead. Toni has been murdered. Tony has vowed to catch her killer. Toni is going to help.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999080,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09892e7","title":"Chew Volume 7: Bad Apples","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493864/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_7_Bad_Apples.jpg","isbn":"978-1607067672","publisher":"Image Comics","pubDate":"2013","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Presenting a new storyline of the New York Times Bestselling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants. Tony Chu — the cibopathic federal agent with the ability to get psychic impressions from what he eats — is back in action, just in time to face a cult of egg-worshipping terrorists who''ve declared holy war on the chicken-eaters of the world.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999079,"hdCover":""},{"id":"09892e6","title":"Chew, Vol. 6: Space Cakes","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493863/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Vol._6_Space_Cakes.jpg","isbn":"978-1607066217","publisher":"Image Comics","pubDate":"2013","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы"],"annotation":"While Tony Chu — the cibopathic federal agent with the ability to get psychic impressions from what he eats — clings to life in a hospital ICU, his twin sister Toni steps up to take center stage. Toni is cibovoyant, able to see the future of anything she eats, and, lately, she’s seeing some pretty terrible things. Presenting a new storyline of the New York Times Bestselling, Harvey and multiple Eisner Award-winning series about cops, crooks, cooks, cannibals, and clairvoyants.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999078,"hdCover":""},{"id":"09892e5","title":"Chew, Volume 5: Major League Chew","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001493862/140/2e83/Dzhon_Lajman_Rob_Gillori__Chew_Volume_5_Major_League_Chew.jpg","isbn":"978-1607065234","publisher":"Image Comics","pubDate":"2012","language":"Английский","series":"Chew","genres":["Комиксы","манга","графические романы"],"annotation":"Tony Chu — the cibopathic federal agent with the ability to get psychic impressions from what he eats — has been kidnapped! He was ambushed, knocked out, brought to a remote location, and bound securely. His captor intends to feed Tony from a menu of his choosing, to find out what Tony can see, in order to learn from him. His daughter, Olive, has been kidnapped for the exact same reason. Two kidnappers, two captives, and two very different outcomes.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999077,"hdCover":""},{"id":"09892e4","title":"Chew Volume 4: Flambe","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236579/140/4d67/Dzhon_Lajman_Rob_Gillori__Chew_Volume_4_Flambe.jpg","isbn":"978-1607063988","publisher":"Image Comics","pubDate":"2011","language":"Английский","series":"Chew","genres":[],"annotation":"These are strange times for Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from the things he eats. Strange writing in extraterrestrial script has appeared in the skies of Planet Earth - and stayed there! People don''''t know if the end days are upon them or not, but they don''''t seem terribly concerned about the laws of the FDA, and what was once the most powerful law enforcement agency is rapidly descending into irrelevancy. So where does that leave the FDA best agent, Tony Chu?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999076,"hdCover":""},{"id":"09892e3","title":"Chew Volume 3: Just Desserts","author":"Джон Лайман, Роб Гиллори","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236578/140/4d67/Dzhon_Lajman_Rob_Gillori__Chew_Volume_3_Just_Desserts.jpg","isbn":"978-1607063353","publisher":"Image Comics","pubDate":"2010","language":"Английский","series":"Chew Book Series","genres":[],"annotation":"Things are looking up for Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from the things he eats. He''s got a girlfriend. He''s got a partner he trusts. He even seems to be getting along with his jerk boss. But his ruthless ex-partner is still out there, operating outside of the law, intending to make good on his threats against Tony and everybody Tony cares about. It''s just a matter of time before their investigations collide, blood spills and, inevitably, body parts are eaten!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999075,"hdCover":""},{"id":"09892e2","title":"Chew Volume 2: International Flavor","author":"Rob Guillory, John Layman","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001236571/140/4d67/Rob_Guillory_John_Layman__Chew_Volume_2_International_Flavor.jpg","isbn":"978-1607062608","publisher":"Image Comics","pubDate":"2010","language":"Английский","series":"Chew","genres":[],"annotation":"Tony Chu, the cibopathic federal agent with the ability to get psychic impressions from the things he eats, is on a bizarre new case. A newly discovered fruit takes Agent Chu to a remote island full of secrets, Presenting the second storyline of IGN.com''s pick for Best Indie Series of 2009 and MTV Splash Page.com''s pick for Best New Series of 2009. Find out what the fuss is about in this latest a twisted and darkly funny comic about cops, crooks, cooks, cannibals and clairvoyants.strangeness-and a shadowy killer with a particularly sinister appetite.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999074,"hdCover":""},{"id":"09892e1","title":"Жуй. Книга 3 (сборник)","author":"Джон Лайман, Роб Гиллори","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002875952/140/06b5/Dzhon_Lajman_Rob_Gillori__Zhuj._Kniga_3_sbornik.jpg","isbn":"978-5-91996-207-6","publisher":"XL Media","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"Тони и Тоня Чжуй — близнецы. Тони — цибопат, а это значит, что он может получать экстрасенсорные впечатления от любой еды, которую ест. А еще Тони может попробовать часть тела умершего человека и узнать, чем тот занимался в прошлом. Тоня — цибо воянт, а это значит, что, укусив любого живого человека, она увидит его будущее. Тони недавно вышибли со службы в особом отделе Федеральной Службы Контроля Продуктов, и он стал простым патрульным Муниципальной дорожной инспек ции, а Тоня — действующий агент НАСА, ныне самой могущественной организации в мире. Теперь именно ей предстоит расследовать всякие странные и загадочные нераскрытые дела...  Перед вами невероятная нарезка из черного юмора, фантастики и умело обыгран ных штампов полицейского боевика, приправленная обязательными ингредиентами второсортного кино: спецагентами, мошенниками, людоедами и экстрасенсами. Вас ждет незабываемое послевкусие, и вы наверняка не откажетесь от добавки! В эту книгу вошли пятая и шестая части серии: «Высшая лига» и «Космические плюшки», а также специальный выпуск о приключениях секретного агента — бойцового петуха Пойо!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Хочу прочитать","read":"","rating":0,"review":"","added":9999073,"hdCover":""}]');
